// AdminFeatureModal.jsx
// Drop this alongside FeatureModal.jsx — it does NOT modify that file.
// Usage: <AdminFeatureModal feature={feature} onSave={handleSave} onClose={handleClose} />

import React, { useState, useEffect, useRef } from "react";
import { PRIORITIES, STATUSES } from "../utils/costants";

const EMPTY = { title: "", description: "", priority: "Medium", status: "Open" };

// ── Inline styles (scoped to this component) ──────────────────────────────────
const S = {
  backdrop: {
    position: "fixed", inset: 0, zIndex: 1000,
    background: "rgba(0,0,0,0.45)", backdropFilter: "blur(3px)",
    display: "flex", alignItems: "center", justifyContent: "center",
    padding: 16,
  },
  modal: {
    background: "#ffffff", borderRadius: 16, width: "100%", maxWidth: 600,
    maxHeight: "90vh", overflowY: "auto",
    boxShadow: "0 8px 40px rgba(0,0,0,0.18)",
    display: "flex", flexDirection: "column",
  },
  header: {
    display: "flex", alignItems: "center", justifyContent: "space-between",
    padding: "18px 22px 14px",
    borderBottom: "1px solid #f3f3f3",
  },
  adminBadge: {
    display: "inline-flex", alignItems: "center", gap: 5,
    background: "#fff8e1", color: "#f57c00",
    border: "1px solid #ffe082",
    borderRadius: 20, padding: "2px 10px", fontSize: 11, fontWeight: 600,
    letterSpacing: 0.5, textTransform: "uppercase",
  },
  titleRow: { display: "flex", alignItems: "center", gap: 10 },
  h2: { margin: 0, fontSize: 17, fontWeight: 600, color: "#1a1a2e" },
  closeBtn: {
    background: "none", border: "none", fontSize: 18,
    cursor: "pointer", color: "#aaa", lineHeight: 1,
    borderRadius: 6, padding: "2px 6px",
    transition: "background 0.15s",
  },
  body: { padding: "18px 22px" },
  field: { marginBottom: 16 },
  label: {
    display: "block", fontSize: 11, fontWeight: 600, marginBottom: 6,
    color: "#888", letterSpacing: "0.5px", textTransform: "uppercase",
  },
  input: {
    width: "100%", padding: "10px 14px", borderRadius: 8,
    border: "1px solid #e8e8e8", fontSize: 14, outline: "none",
    boxSizing: "border-box", background: "#fafafa",
    transition: "border-color 0.15s, background 0.15s",
    color: "#1a1a2e",
  },
  inputError: { borderColor: "#e53e3e", background: "#fff8f8" },
  textarea: {
    width: "100%", padding: "10px 14px", borderRadius: 8,
    border: "1px solid #e8e8e8", fontSize: 14, resize: "vertical",
    outline: "none", boxSizing: "border-box",
    background: "#fafafa", color: "#1a1a2e",
  },
  select: {
    width: "100%", padding: "10px 14px", borderRadius: 8,
    border: "1px solid #e8e8e8", fontSize: 14, outline: "none",
    background: "#fafafa", cursor: "pointer", color: "#1a1a2e",
  },
  fieldRow: { display: "flex", gap: 14, marginBottom: 16 },
  errorMsg: { display: "block", color: "#e53e3e", fontSize: 12, marginTop: 4 },

  // ── Admin Image Panel ──────────────────────────────────────────────────────
  imagePanel: {
    border: "1px solid #eeeeee",
    borderRadius: 12, overflow: "hidden",
    background: "#fafafa",
  },
  imagePanelHeader: {
    display: "flex", alignItems: "center", justifyContent: "space-between",
    padding: "10px 14px",
    background: "#fff8e1", borderBottom: "1px solid #f3e5ab",
  },
  imagePanelTitle: {
    display: "flex", alignItems: "center", gap: 6,
    fontWeight: 600, fontSize: 13, color: "#e65100",
  },
  imagePanelBody: { padding: 14 },
  tabRow: {
    display: "flex", gap: 4, marginBottom: 14,
    background: "#eeeeee", borderRadius: 8, padding: 4,
  },
  tabBtn: (active) => ({
    flex: 1, padding: "7px 0", border: "none", cursor: "pointer",
    fontSize: 13, fontWeight: active ? 600 : 500,
    background: active ? "#6c63ff" : "transparent",
    color: active ? "#fff" : "#777",
    borderRadius: 6,
    transition: "background 0.15s, color 0.15s",
  }),
  // ── No dashed border — solid fill only ──
  dropZone: (dragging) => ({
    border: "none",
    borderRadius: 10, padding: "32px 16px",
    textAlign: "center", cursor: "pointer",
    background: dragging ? "#ede9fe" : "#f0f0f0",
    transition: "background 0.2s",
    userSelect: "none",
  }),
  previewWrap: { position: "relative", display: "inline-block", width: "100%" },
  previewImg: {
    display: "block", width: "100%", maxHeight: 200,
    borderRadius: 10, border: "none", objectFit: "cover",
  },
  previewChangeBtn: {
    position: "absolute", bottom: 8, left: 8,
    background: "rgba(108,99,255,0.90)", color: "#fff",
    borderRadius: 6, padding: "4px 12px", fontSize: 12,
    fontWeight: 600, cursor: "pointer", border: "none",
  },
  previewRemoveBtn: {
    position: "absolute", top: 6, right: 6,
    background: "rgba(0,0,0,0.50)", color: "#fff",
    border: "none", borderRadius: "50%",
    width: 26, height: 26, fontSize: 14,
    cursor: "pointer", display: "flex",
    alignItems: "center", justifyContent: "center",
  },
  urlInput: {
    width: "100%", padding: "10px 14px", borderRadius: 8,
    border: "1px solid #e8e8e8", fontSize: 13, outline: "none",
    boxSizing: "border-box", marginBottom: 8,
    background: "#fff", color: "#1a1a2e",
  },
  urlApplyBtn: {
    padding: "8px 18px", borderRadius: 8, border: "none",
    background: "#6c63ff", color: "#fff",
    fontSize: 13, fontWeight: 600, cursor: "pointer",
  },
  urlError: { color: "#e53e3e", fontSize: 12, marginTop: 4 },

  footer: {
    display: "flex", justifyContent: "flex-end", gap: 10,
    padding: "14px 22px",
    borderTop: "1px solid #f3f3f3",
  },
  btnGhost: {
    padding: "9px 20px", borderRadius: 8,
    border: "1px solid #e0e0e0", background: "#fff",
    fontSize: 14, cursor: "pointer", fontWeight: 500, color: "#555",
  },
  btnPrimary: {
    padding: "9px 22px", borderRadius: 8, border: "none",
    background: "#6c63ff", color: "#fff",
    fontSize: 14, fontWeight: 600, cursor: "pointer",
  },
};

export default function AdminFeatureModal({ feature, onSave, onClose }) {
  const [form, setForm] = useState(feature ? { ...feature } : { ...EMPTY });
  const [errors, setErrors] = useState({});

  // ── Image state ─────────────────────────────────────────────────────────────
  const [imageFile, setImageFile]       = useState(null);
  const [imagePreview, setImagePreview] = useState(feature?.imageUrl || null);
  const [dragging, setDragging]         = useState(false);
  const [tab, setTab]                   = useState("upload");   // "upload" | "url"
  const [urlInput, setUrlInput]         = useState("");
  const [urlError, setUrlError]         = useState("");

  const titleRef   = useRef(null);
  const fileInputRef = useRef(null);
  const changeInputRef = useRef(null);

  const isEdit = Boolean(feature);

  useEffect(() => { titleRef.current?.focus(); }, []);
  useEffect(() => {
    const handler = (e) => { if (e.key === "Escape") onClose(); };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, [onClose]);

  // ── Validation ──────────────────────────────────────────────────────────────
  function validate() {
    const errs = {};
    if (!form.title.trim()) errs.title = "Title is required.";
    else if (form.title.trim().length < 3) errs.title = "Title must be at least 3 characters.";
    if (!form.description.trim()) errs.description = "Description is required.";
    return errs;
  }

  function handleChange(e) {
    const { name, value } = e.target;
    setForm((f) => ({ ...f, [name]: value }));
    if (errors[name]) setErrors((er) => ({ ...er, [name]: undefined }));
  }

  function handleSubmit(e) {
    e.preventDefault();
    const errs = validate();
    if (Object.keys(errs).length) { setErrors(errs); return; }
    // Pass imageFile (File object) OR imageUrl (string) to onSave
    onSave({
      ...form,
      image: imageFile,
      imageUrl: imageFile ? undefined : (imagePreview || undefined),
    });
    onClose();
  }

  // ── Image helpers ────────────────────────────────────────────────────────────
  function applyFile(file) {
    if (!file || !file.type.startsWith("image/")) return;
    setImageFile(file);
    setImagePreview(URL.createObjectURL(file));
    setUrlInput("");
    setUrlError("");
  }

  function handleDrop(e) {
    e.preventDefault();
    setDragging(false);
    applyFile(e.dataTransfer.files[0]);
  }

  function removeImage() {
    setImageFile(null);
    setImagePreview(null);
    setUrlInput("");
    setUrlError("");
    if (fileInputRef.current)    fileInputRef.current.value = "";
    if (changeInputRef.current)  changeInputRef.current.value = "";
  }

  function applyUrlImage() {
    const url = urlInput.trim();
    if (!url) { setUrlError("Please enter a URL."); return; }
    try { new URL(url); } catch { setUrlError("Invalid URL."); return; }
    setUrlError("");
    setImageFile(null);
    setImagePreview(url);
  }

  // ── Render ───────────────────────────────────────────────────────────────────
  return (
    <div style={S.backdrop} onClick={(e) => e.target === e.currentTarget && onClose()}>
      <div style={S.modal} role="dialog" aria-modal="true"
           aria-label={isEdit ? "Admin: Edit Feature" : "Admin: New Feature"}>

        {/* ── Header ── */}
        <div style={S.header}>
          <div style={S.titleRow}>
            <h2 style={S.h2}>{isEdit ? "Edit Request" : "New Request"}</h2>
            <span style={S.adminBadge}>🛡 Admin</span>
          </div>
          <button style={S.closeBtn} onClick={onClose} aria-label="Close">✕</button>
        </div>

        <form onSubmit={handleSubmit} noValidate>
          <div style={S.body}>

            {/* Title */}
            <div style={S.field}>
              <label style={S.label} htmlFor="adm-title">Title</label>
              <input
                ref={titleRef}
                id="adm-title" name="title" type="text"
                value={form.title} onChange={handleChange}
                placeholder="Short, descriptive title..."
                style={{ ...S.input, ...(errors.title ? S.inputError : {}) }}
                autoComplete="off"
              />
              {errors.title && <span style={S.errorMsg}>{errors.title}</span>}
            </div>

            {/* Description */}
            <div style={S.field}>
              <label style={S.label} htmlFor="adm-description">Description</label>
              <textarea
                id="adm-description" name="description"
                value={form.description} onChange={handleChange}
                placeholder="What should this feature do?"
                rows={4}
                style={{ ...S.textarea, ...(errors.description ? S.inputError : {}) }}
              />
              {errors.description && <span style={S.errorMsg}>{errors.description}</span>}
            </div>

            {/* Priority + Status */}
            <div style={S.fieldRow}>
              <div style={{ flex: 1 }}>
                <label style={S.label} htmlFor="adm-priority">Priority</label>
                <select id="adm-priority" name="priority"
                        value={form.priority} onChange={handleChange} style={S.select}>
                  {PRIORITIES.map((p) => <option key={p} value={p}>{p}</option>)}
                </select>
              </div>
              <div style={{ flex: 1 }}>
                <label style={S.label} htmlFor="adm-status">Status</label>
                <select id="adm-status" name="status"
                        value={form.status} onChange={handleChange} style={S.select}>
                  {STATUSES.map((s) => <option key={s} value={s}>{s}</option>)}
                </select>
              </div>
            </div>

            {/* ── Admin Image Panel ── */}
            <div style={S.field}>
              <label style={S.label}>
                Image&nbsp;
                <span style={{ fontWeight: 400, color: "#888", fontSize: 12 }}>(optional)</span>
              </label>

              <div style={S.imagePanel}>
                {/* Panel header */}
                <div style={S.imagePanelHeader}>
                  <span style={S.imagePanelTitle}>
                    🖼️ Image Management
                  </span>
                  {imagePreview && (
                    <button type="button" onClick={removeImage}
                      style={{
                        background: "#fbe9e7", color: "#bf360c",
                        border: "1px solid #ffab91", borderRadius: 5,
                        padding: "3px 10px", fontSize: 12,
                        fontWeight: 600, cursor: "pointer",
                      }}>
                      ✕ Remove Image
                    </button>
                  )}
                </div>

                <div style={S.imagePanelBody}>
                  {imagePreview ? (
                    /* ── Preview with replace controls ── */
                    <div>
                      <div style={S.previewWrap}>
                        <img src={imagePreview} alt="preview" style={S.previewImg} />
                        <label style={S.previewChangeBtn}>
                          📁 Replace
                          <input
                            ref={changeInputRef}
                            type="file" accept="image/*"
                            style={{ display: "none" }}
                            onChange={(e) => applyFile(e.target.files[0])}
                          />
                        </label>
                      </div>
                      <p style={{ fontSize: 12, color: "#888", margin: "8px 0 0" }}>
                        {imageFile
                          ? `📎 ${imageFile.name} (${(imageFile.size / 1024).toFixed(1)} KB)`
                          : "🔗 Loaded from URL"}
                      </p>
                    </div>
                  ) : (
                    /* ── No image: tabbed upload / URL ── */
                    <div>
                      <div style={S.tabRow}>
                        <button type="button" style={S.tabBtn(tab === "upload")}
                                onClick={() => setTab("upload")}>
                          📁 Upload File
                        </button>
                        <button type="button" style={S.tabBtn(tab === "url")}
                                onClick={() => setTab("url")}>
                          🔗 Image URL
                        </button>
                      </div>

                      {tab === "upload" ? (
                        <div
                          onDragOver={(e) => { e.preventDefault(); setDragging(true); }}
                          onDragLeave={() => setDragging(false)}
                          onDrop={handleDrop}
                          onClick={() => fileInputRef.current?.click()}
                          style={S.dropZone(dragging)}
                        >
                          <div style={{ fontSize: 32, marginBottom: 6 }}>🖼️</div>
                          <div style={{ color: "#555", fontSize: 14 }}>
                            Drag & drop an image, or{" "}
                            <span style={{ color: "#6c63ff", fontWeight: 600 }}>browse</span>
                          </div>
                          <div style={{ color: "#aaa", fontSize: 12, marginTop: 4 }}>
                            PNG, JPG, GIF, WEBP supported
                          </div>
                          <input
                            ref={fileInputRef}
                            type="file" accept="image/*"
                            style={{ display: "none" }}
                            onChange={(e) => applyFile(e.target.files[0])}
                          />
                        </div>
                      ) : (
                        <div>
                          <input
                            type="url"
                            value={urlInput}
                            onChange={(e) => { setUrlInput(e.target.value); setUrlError(""); }}
                            placeholder="https://example.com/image.png"
                            style={S.urlInput}
                          />
                          {urlError && <div style={S.urlError}>{urlError}</div>}
                          <button type="button" style={S.urlApplyBtn} onClick={applyUrlImage}>
                            Apply URL
                          </button>
                        </div>
                      )}
                    </div>
                  )}
                </div>
              </div>
            </div>
            {/* ─────────────────────────────────────────────────────────── */}

          </div>

          {/* ── Footer ── */}
          <div style={S.footer}>
            <button type="button" style={S.btnGhost} onClick={onClose}>Cancel</button>
            <button type="submit" style={S.btnPrimary}>
              {isEdit ? "Save Changes" : "Add Request"}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}
